code = """import json

# Calculate FTFT volatility in Python
ftft_file = locals()['var_functions.query_db:106']
if isinstance(ftft_file, list):
    ftft_data = ftft_file
else:
    with open(ftft_file, 'r') as f:
        ftft_data = json.load(f)

ftft_high_vol = 0
for day in ftft_data:
    high = float(day['High'])
    low = float(day['Low'])
    if low > 0 and (high - low) > (low * 0.2):
        ftft_high_vol += 1

# Calculate BCLI volatility  
bcli_file = locals()['var_functions.query_db:110']
if isinstance(bcli_file, list):
    bcli_data = bcli_file
else:
    with open(bcli_file, 'r') as f:
        bcli_data = json.load(f)

bcli_high_vol = 0
for day in bcli_data:
    high = float(day['High'])
    low = float(day['Low'])
    if low > 0 and (high - low) > (low * 0.2):
        bcli_high_vol += 1

print(f"FTFT: {ftft_high_vol}/{len(ftft_data)} days")
print(f"BCLI: {bcli_high_vol}/{len(bcli_data)} days")

print("__RESULT__:")
print(json.dumps({
    'FTFT': {'high_vol_days': ftft_high_vol, 'total_days': len(ftft_data)},
    'BCLI': {'high_vol_days': bcli_high_vol, 'total_days': len(bcli_data)}
}))"""

